gen.py:
```
#!/usr/bin/env python
from __future__ import print_function
import itertools
import sys

head='''
group edgerouters {
    peer-as 65100;
    local-as 65101;
    hold-time 3600;
    local-address 127.0.0.1;
    graceful-restart 1200;
    group-updates;

    md5 'removed';
    static {
'''

route = '       route {}/32 next-hop self community [ 65101:666 no-export ] ;'.format
#route = '       route {}/32 next-hop 127.0.0.1 community [ no-export ] ;'.format

tail='''
    }

    family {
      inet4 unicast;
    }

    neighbor 192.168.2.240 {
        description "one";
    }
    neighbor 192.168.2.241 {
        description "two";
    }
    neighbor 192.168.2.242 {
        description "three";
    }

}
'''

def ips(number):
    r = range(1,256)
    t = "{}.{}.{}.{}".format
    it = itertools.product(r,r,r,r)
    it = itertools.islice(it, number)
    for octets in it:
        yield(t(*octets))

if __name__ == "__main__":
    number_of_routes = int(sys.argv[1])
    print(head)
    for ip in ips(number_of_routes):
        print(route(ip))
    print(tail)

```

